		$combo_section->ListData = $combo_section->ListItem;
	}
	$combo_section->SelectName = 'section';

	if($hasSelectedId) {
		if(!($row = getRecord('newsletter_table', $selectedId))) {
			return error_message($Translation['No records found'], 'newsletter_table_view.php', false);
		}
		$combo_section->SelectedData = $row['section'];
		$urow = $row; /* unsanitized data */
		$row = array_map('safe_html', $row);
	} else {
		$filterField = Request::val('FilterField');
